// SPDX-License-Identifier: MIT
pragma solidity ^0.8.17;

contract SecureAuction {

    struct Auction {
        address payable seller;
        uint startTime;
        uint endTime;
        bool ended;
        address highestBidder;
        uint highestBid;
        uint minIncrement;
        uint extensionTime;
        uint maxBid;
    }

    uint public auctionCount;
    mapping(uint => Auction) public auctions;
    mapping(address => uint) public pendingReturns;
    mapping(address => bool) private hasPendingRecorded;
    address[] public pendingParties;

    bool private locked;

    event AuctionCreated(uint auctionId, address seller);
    event HighestBidIncreased(uint auctionId, address bidder, uint amount);
    event AuctionExtended(uint auctionId, uint newEndTime);
    event AuctionEnded(uint auctionId, address winner, uint amount);
    event AuctionCancelled(uint auctionId);
    event Withdrawn(address indexed who, uint amount);
    event WithdrawFailed(address indexed who, uint amount);

    modifier noReentrant() {
        require(!locked, "Reentrant call");
        locked = true;
        _;
        locked = false;
    }

    function createAuction(
        uint _biddingTime,
        uint _minIncrement,
        uint _extensionTime,
        uint _maxBid
    ) external {
        require(_biddingTime > 0, "Invalid bidding time");
        require(_minIncrement > 0, "Invalid min increment");

        auctionCount++;

        auctions[auctionCount] = Auction({
            seller: payable(msg.sender),
            startTime: block.timestamp,
            endTime: block.timestamp + _biddingTime,
            ended: false,
            highestBidder: address(0),
            highestBid: 0,
            minIncrement: _minIncrement,
            extensionTime: _extensionTime,
            maxBid: _maxBid
        });

        emit AuctionCreated(auctionCount, msg.sender);
    }

    function bid(uint auctionId) external payable {
        Auction storage auction = auctions[auctionId];

        require(block.timestamp >= auction.startTime, "Not started");
        require(block.timestamp < auction.endTime, "Auction ended");
        require(!auction.ended, "Already ended");
        require(msg.sender != auction.seller, "Seller cannot bid");

        uint required = auction.highestBid + auction.minIncrement;
        require(msg.value >= required, "Bid below min increment");

        if (auction.maxBid != 0) {
            require(msg.value <= auction.maxBid, "Above maxBid");
        }

        if (auction.highestBid != 0) {
            pendingReturns[auction.highestBidder] += auction.highestBid;

            if (!hasPendingRecorded[auction.highestBidder]) {
                hasPendingRecorded[auction.highestBidder] = true;
                pendingParties.push(auction.highestBidder);
            }
        }

        auction.highestBidder = msg.sender;
        auction.highestBid = msg.value;

        if (auction.endTime - block.timestamp < auction.extensionTime) {
            auction.endTime += auction.extensionTime;
            emit AuctionExtended(auctionId, auction.endTime);
        }

        emit HighestBidIncreased(auctionId, msg.sender, msg.value);
    }

    function endAuction(uint auctionId) external noReentrant {
        Auction storage auction = auctions[auctionId];

        require(msg.sender == auction.seller, "Only seller");
        require(block.timestamp >= auction.endTime, "Not ended yet");
        require(!auction.ended, "Already ended");

        auction.ended = true;

        emit AuctionEnded(auctionId, auction.highestBidder, auction.highestBid);

        uint amount = auction.highestBid;
        auction.highestBid = 0;

        if (amount > 0) {
            (bool success, ) = auction.seller.call{value: amount}("");

            if (!success) {
                pendingReturns[auction.seller] += amount;

                if (!hasPendingRecorded[auction.seller]) {
                    hasPendingRecorded[auction.seller] = true;
                    pendingParties.push(auction.seller);
                }
            }
        }
    }

    function cancelAuction(uint auctionId) external noReentrant {
        Auction storage auction = auctions[auctionId];

        require(msg.sender == auction.seller, "Only seller");
        require(!auction.ended, "Already ended");

        auction.ended = true;

        emit AuctionCancelled(auctionId);

        if (auction.highestBid != 0) {
            pendingReturns[auction.highestBidder] += auction.highestBid;

            if (!hasPendingRecorded[auction.highestBidder]) {
                hasPendingRecorded[auction.highestBidder] = true;
                pendingParties.push(auction.highestBidder);
            }

            auction.highestBid = 0;
        }
    }

    function withdraw() external noReentrant returns (bool) {
        uint amount = pendingReturns[msg.sender];
        require(amount > 0, "No funds");

        pendingReturns[msg.sender] = 0;

        (bool success, ) = payable(msg.sender).call{value: amount}("");

        if (!success) {
            pendingReturns[msg.sender] = amount;
            emit WithdrawFailed(msg.sender, amount);
            return false;
        }

        emit Withdrawn(msg.sender, amount);
        return true;
    }

    function getPendingParties() external view returns (address[] memory) {
        return pendingParties;
    }

    receive() external payable {
        revert("Direct deposits not accepted");
    }
}

contract SealedBidAuction {

    struct SealedAuction {
        address payable seller;
        uint startTime;
        uint biddingEnd;
        uint revealEnd;
        bool finalized;
        address winner;
        uint winningBid;
    }

    struct BidCommitment {
        bytes32 commitment;
        uint bond;
        bool revealed;
        uint revealedAmount;
    }

    uint public sealedAuctionCount;

    mapping(uint => SealedAuction) public sealedAuctions;
    mapping(uint => mapping(address => BidCommitment)) public commitments;
    mapping(uint => address[]) private bidders;
    mapping(uint => mapping(address => bool)) private hasBid;
    mapping(address => uint) public pendingRefunds;

    bool private locked;

    event SealedAuctionCreated(uint indexed auctionId, address seller, uint biddingEnd, uint revealEnd);
    event BidCommitted(uint indexed auctionId, address indexed bidder);
    event BidRevealed(uint indexed auctionId, address indexed bidder, uint amount, bool valid);
    event SealedAuctionFinalized(uint indexed auctionId, address winner, uint amount);
    event RefundWithdrawn(address indexed who, uint amount);

    modifier noReentrant() {
        require(!locked, "Reentrant call");
        locked = true;
        _;
        locked = false;
    }

    function makeCommitment(
        uint amount,
        bytes32 nonce,
        address bidder
    ) external pure returns (bytes32) {
        return keccak256(abi.encodePacked(amount, nonce, bidder));
    }

    function createSealedAuction(
        uint _biddingDuration,
        uint _revealDuration
    ) external returns (uint auctionId) {
        require(_biddingDuration > 0, "Invalid bidding duration");
        require(_revealDuration > 0, "Invalid reveal duration");

        sealedAuctionCount++;
        auctionId = sealedAuctionCount;

        uint biddingEnd_ = block.timestamp + _biddingDuration;

        sealedAuctions[auctionId] = SealedAuction({
            seller: payable(msg.sender),
            startTime: block.timestamp,
            biddingEnd: biddingEnd_,
            revealEnd: biddingEnd_ + _revealDuration,
            finalized: false,
            winner: address(0),
            winningBid: 0
        });

        emit SealedAuctionCreated(auctionId, msg.sender, biddingEnd_, biddingEnd_ + _revealDuration);
    }

    function commitBid(uint auctionId, bytes32 commitment) external payable {
        SealedAuction storage sa = sealedAuctions[auctionId];

        require(block.timestamp >= sa.startTime, "Not started");
        require(block.timestamp < sa.biddingEnd, "Bidding closed");
        require(!sa.finalized, "Auction finalized");
        require(msg.sender != sa.seller, "Seller cannot bid");
        require(msg.value > 0, "Bond required");
        require(commitments[auctionId][msg.sender].bond == 0, "Already committed");

        commitments[auctionId][msg.sender] = BidCommitment({
            commitment: commitment,
            bond: msg.value,
            revealed: false,
            revealedAmount: 0
        });

        if (!hasBid[auctionId][msg.sender]) {
            hasBid[auctionId][msg.sender] = true;
            bidders[auctionId].push(msg.sender);
        }

        emit BidCommitted(auctionId, msg.sender);
    }

    function updateBid(uint auctionId, bytes32 newCommitment) external payable {
        SealedAuction storage sa = sealedAuctions[auctionId];
        BidCommitment storage bc = commitments[auctionId][msg.sender];

        require(block.timestamp < sa.biddingEnd, "Bidding closed");
        require(!sa.finalized, "Auction finalized");
        require(bc.bond > 0, "No existing commitment");

        bc.commitment = newCommitment;
        bc.bond += msg.value;

        emit BidCommitted(auctionId, msg.sender);
    }

    function revealBid(uint auctionId, uint amount, bytes32 nonce) external noReentrant {
        SealedAuction storage sa = sealedAuctions[auctionId];
        BidCommitment storage bc = commitments[auctionId][msg.sender];

        require(block.timestamp >= sa.biddingEnd, "Reveal not open yet");
        require(block.timestamp < sa.revealEnd, "Reveal phase over");
        require(!sa.finalized, "Auction finalized");
        require(bc.bond > 0, "No commitment found");
        require(!bc.revealed, "Already revealed");

        bc.revealed = true;

        bytes32 expected = keccak256(abi.encodePacked(amount, nonce, msg.sender));
        bool valid = (expected == bc.commitment) && (bc.bond >= amount) && (amount > 0);

        if (valid) {
            bc.revealedAmount = amount;

            uint excess = bc.bond - amount;
            if (excess > 0) {
                pendingRefunds[msg.sender] += excess;
            }

            if (amount > sa.winningBid) {
                if (sa.winningBid > 0) {
                    pendingRefunds[sa.winner] += sa.winningBid;
                }
                sa.winner = msg.sender;
                sa.winningBid = amount;
            } else {
                pendingRefunds[msg.sender] += amount;
            }
        } else {
            pendingRefunds[sa.seller] += bc.bond;
        }

        emit BidRevealed(auctionId, msg.sender, amount, valid);
    }

    function finalizeAuction(uint auctionId) external noReentrant {
        SealedAuction storage sa = sealedAuctions[auctionId];

        require(block.timestamp >= sa.revealEnd, "Reveal phase not over");
        require(!sa.finalized, "Already finalized");

        sa.finalized = true;

        emit SealedAuctionFinalized(auctionId, sa.winner, sa.winningBid);

        if (sa.winningBid > 0) {
            uint amount = sa.winningBid;
            sa.winningBid = 0;

            (bool success, ) = sa.seller.call{value: amount}("");
            if (!success) {
                pendingRefunds[sa.seller] += amount;
            }
        }
    }

    function withdrawRefund() external noReentrant returns (bool) {
        uint amount = pendingRefunds[msg.sender];
        require(amount > 0, "Nothing to withdraw");

        pendingRefunds[msg.sender] = 0;
        (bool success, ) = payable(msg.sender).call{value: amount}("");

        if (!success) {
            pendingRefunds[msg.sender] = amount;
            return false;
        }

        emit RefundWithdrawn(msg.sender, amount);
        return true;
    }

    function getBidders(uint auctionId) external view returns (address[] memory) {
        return bidders[auctionId];
    }

    receive() external payable {
        revert("Direct deposits not accepted");
    }
}
